SELECT MAX(era) AS highest_era
FROM pitching_performances
WHERE game_id = 1;

SELECT analytics_results
FROM game_analytics
WHERE game_id = 1;

SELECT AVG(game_score) AS avg_game_score
FROM pitching_performances
WHERE team_id = 1;

SELECT g.sport, AVG(g.attendance) AS average_attendance
FROM games g
GROUP BY g.sport;

SELECT AVG(duration) AS avg_duration
FROM game_access
WHERE access_type = 'download';
